function DocumentEditor({ docId, userId }) {
  const [content, setContent] = useState('');
  const [isOnline, setIsOnline] = useState(navigator.onLine);

  // Load document when docId changes.
  useEffect(() => {
    loadDocument(docId).then(setContent);
  }, [docId]);

  // Track online status separately; unrelated to document loading.
  useEffect(() => {
    function handleOnline() { setIsOnline(true); }
    function handleOffline() { setIsOnline(false); }
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);
    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  return <Editor content={content} readOnly={!isOnline} onChange={setContent} />;
}
